var _a;export class TextDB{constructor(key){this.getReadOnlyLink=async()=>`${TextDB.API_URL}/${await this.getReadOnlyKey()}`;this.getReadOnlyKey=async()=>{const PAGE_URL="https://textdb.dev/data";const extractReadOnlyKey=html=>{const regex=/<section class="data-api">[\s\S]*?<a href="https:\/\/textdb\.dev\/data\/([^"]*)">[\s\S]*?<\/section>/;const match=html.match(regex);if(match){return match[1]}return null};const response=await fetch(`${PAGE_URL}/${this.key}`,{method:"GET"});return extractReadOnlyKey(await response.text())};this.read=async()=>{const response=await fetch(`${TextDB.API_URL}/${this.key}`);return response.text()};this.write=async text=>fetch(`${TextDB.API_URL}/${this.key}`,{body:text,headers:{"Content-Type":"text/plain"},method:"POST"});this.url=()=>TextDB.API_URL+"/"+this.key;this.randomKey=(n=3)=>{let chars="abcdefghjkmnpqrstuvwxyz";let result="";for(let i=0;i<3;i++){for(let j=0;j<n;j++){result+=chars[Math.floor(Math.random()*chars.length)]}if(i<2)result+="-"}return result};this.key=key||this.randomKey(3)}}_a=TextDB;TextDB.API_URL="https://textdb.dev/api/data";TextDB.SHORT_HASH_LENGTH=6;TextDB.read=async key=>new TextDB(key).read();TextDB.write=async(key,text)=>new TextDB(key).write(text);TextDB.url=key=>new TextDB(key).url();TextDB.randomKey=()=>(new TextDB).randomKey();
